  ('pukao-77f8735d-moex-00022', 'pukao-77f8735d', 'pukao-77f8735d-moex-114-85716566', 'sub-pukao-77f8735d-03', NULL, 'single_choice', '政府為建構國人健康飲食的支持性環境，於民國113年所實施的重要措施為何？', '["當年完成全國22個縣市，每縣市至少設有1個社區營養推廣中心的措施", "補助各縣市實施國中小學採用在地食材團膳，提供免費營養午餐", "通過不適合兒童長期食用之食品廣告及促銷管理辦法，禁止五類不利兒童健康食品於兒少頻道 播放廣告，也不得以贈送玩具促銷", "公布實施營養及健康飲食促進法"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:04+00:00", "source_pdf_sha1": "a166b3a132a4", "answer_pdf_sha1": "de8cffdf0241", "source_family": "moex-gov-tw", "moex": {"exam_code": "114080", "c": "424", "s": "2005", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "衛生行政學概要", "year": "114", "exam_name": "114年公務人員高等考試三級考試暨普通考試", "original_question_number": 11, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "衛生行政"}'::jsonb, NULL),
  ('pukao-77f8735d-moex-00023', 'pukao-77f8735d', 'pukao-77f8735d-moex-114-85716566', 'sub-pukao-77f8735d-03', NULL, 'single_choice', '為於2030年達到我國癌症標準化死亡率減少三分之一的目標，以落實健康臺灣的願景，114年衛 生福利部擴大癌症防治計畫內容，下列何者非其主要的內容？', '["全面擴大國人公費癌症篩檢範疇", "增加肺癌、肝癌、乳癌、大腸癌及口腔癌等五大癌症之篩檢項目", "乳癌篩檢年齡延伸40～44歲及70～74歲女性", "肺癌檢查，於男性具家族史者，將年齡放寬至45～74歲"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:04+00:00", "source_pdf_sha1": "a166b3a132a4", "answer_pdf_sha1": "de8cffdf0241", "source_family": "moex-gov-tw", "moex": {"exam_code": "114080", "c": "424", "s": "2005", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "衛生行政學概要", "year": "114", "exam_name": "114年公務人員高等考試三級考試暨普通考試", "original_question_number": 12, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "衛生行政"}'::jsonb, NULL),
